import sys, ctypes, tempfile, subprocess, os

C_SRC = r"""
long long mandel_count(long long width, long long height, long long max_iter) {
    long long total = 0;
    for (long long py = 0; py < height; py++) {
        for (long long px = 0; px < width; px++) {
            double x0 = (double)px / width * 3.5 - 2.5;
            double y0 = (double)py / height * 2.0 - 1.0;
            double x = 0.0, y = 0.0;
            long long it = 0;
            while (x*x + y*y <= 4.0 && it < max_iter) {
                double xt = x*x - y*y + x0;
                y = 2.0*x*y + y0;
                x = xt;
                it++;
            }
            if (it >= max_iter) total++;
        }
    }
    return total;
}
"""

def build_lib():
    d = tempfile.mkdtemp()
    src = os.path.join(d, "m.c")
    so = os.path.join(d, "m.so")
    with open(src, "w") as f:
        f.write(C_SRC)
    cc = os.environ.get("CC", "cc")
    subprocess.run([cc, "-O2", "-shared", "-fPIC", "-o", so, src], check=True)
    return so

def main():
    data = sys.stdin.read().split()
    w = int(data[0]); h = int(data[1]); mi = int(data[2])
    so = build_lib()
    lib = ctypes.CDLL(so)
    lib.mandel_count.restype = ctypes.c_longlong
    lib.mandel_count.argtypes = [ctypes.c_longlong] * 3
    print(lib.mandel_count(w, h, mi))

main()
